import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class CommandInjectionExample {

    public static void main(String[] args) {
        try {
            BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter a directory name: ");
            String directoryName = br.readLine();

            // Vulnerable code - user input is directly passed to the command
            Process p = Runtime.getRuntime().exec("ls " + directoryName);
            BufferedReader commandOutput = new BufferedReader(new InputStreamReader(p.getInputStream()));

            String line;
            while ((line = commandOutput.readLine()) != null) {
                System.out.println(line);
            }

        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

